class Solution:
    def racecar(self, target: int) -> int:
        from collections import deque
        queue = deque([(0, 1)])
        visited = set([(0, 1)])
        steps = 0
        while queue:
            for _ in range(len(queue)):
                position, speed = queue.popleft()
                if position == target:
                    return steps
                if (position + speed, speed * 2) not in visited:
                    queue.append((position + speed, speed * 2))
                    visited.add((position + speed, speed * 2))
                if speed > 0:
                    new_speed = -1
                else:
                    new_speed = 1
                if (position, new_speed) not in visited:
                    queue.append((position, new_speed))
                    visited.add((position, new_speed))
            steps += 1
```
